func ProjectIDIsNil() predicate.TMEntry {
	return predicate.TMEntry(sql.FieldIsNull(FieldProjectID))
}

// ProjectIDNotNil applies the NotNil predicate on the "project_id" field.
func ProjectIDNotNil() predicate.TMEntry {
	return predicate.TMEntry(sql.FieldNotNull(FieldProjectID))
}

// HasProject applies the HasEdge predicate on the "project" edge.
func HasProject() predicate.TMEntry {
	return predicate.TMEntry(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ProjectTable, ProjectColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasProjectWith applies the HasEdge predicate on the "project" edge with a given conditions (other predicates).
func HasProjectWith(preds ...predicate.Project) predicate.TMEntry {
	return predicate.TMEntry(func(s *sql.Selector) {
		step := newProjectStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.TMEntry) predicate.TMEntry {
	return predicate.TMEntry(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.TMEntry) predicate.TMEntry {
	return predicate.TMEntry(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.TMEntry) predicate.TMEntry {
	return predicate.TMEntry(sql.NotPredicates(p))
}
